// apiService.js

const API_BASE_URL = 'https://api.example.com';

let authToken = null; // Store the authentication token

// --- Helper for API requests ---
async function request(endpoint, method = 'GET', data = null, requiresAuth = true) {
  const url = `${API_BASE_URL}${endpoint}`;
  const headers = {
    'Content-Type': 'application/json',
  };

  if (requiresAuth && authToken) {
    headers['Authorization'] = `Bearer ${authToken}`;
  }

  const config = {
    method,
    headers,
  };

  if (data) {
    config.body = JSON.stringify(data);
  }

  try {
    const response = await fetch(url, config);
    const responseData = await response.json();

    if (!response.ok) {
      // Handle API errors (e.g., 401 Unauthorized, 404 Not Found, 500 Server Error)
      const error = new Error(responseData.message || `API Error: ${response.status} ${response.statusText}`);
      error.status = response.status;
      error.data = responseData; // Include response data for more context
      throw error;
    }

    return responseData;
  } catch (error) {
    console.error(`API request failed for ${method} ${url}:`, error);
    throw error; // Re-throw to be handled by the caller
  }
}

// --- Authentication ---

/**
 * Sets the authentication token for subsequent requests.
 * @param {string} token The JWT token received after login/registration.
 */
export const setAuthToken = (token) => {
  authToken = token;
};

/**
 * Clears the authentication token.
 */
export const clearAuthToken = () => {
  authToken = null;
};

/**
 * Authenticates a user.
 * @param {string} email User's email.
 * @param {string} password User's password.
 * @returns {Promise<object>} An object containing user data and the authentication token.
 */
export const login = async (email, password) => {
  const response = await request('/auth/login', 'POST', { email, password }, false);
  if (response.token) {
    setAuthToken(response.token);
  }
  return response; // Expects { user: {...}, token: "..." }
};

/**
 * Registers a new user.
 * @param {string} email User's email.
 * @param {string} password User's password.
 * @param {string} name User's name.
 * @returns {Promise<object>} An object containing user data and the authentication token.
 */
export const register = async (email, password, name) => {
  const response = await request('/auth/register', 'POST', { email, password, name }, false);
  if (response.token) {
    setAuthToken(response.token);
  }
  return response; // Expects { user: {...}, token: "..." }
};

// --- User Profile ---

/**
 * Fetches the currently authenticated user's profile.
 * @returns {Promise<object>} The user's profile data.
 */
export const fetchUserProfile = async () => {
  return request('/profile', 'GET'); // Requires auth
};

/**
 * Updates the currently authenticated user's profile.
 * @param {object} profileData The data to update (e.g., { name: 'New Name', bio: '...' }).
 * @returns {Promise<object>} The updated user's profile data.
 */
export const updateUserProfile = async (profileData) => {
  return request('/profile', 'PUT', profileData); // Requires auth
};

// --- Example Data Operations (assuming common patterns) ---

/**
 * Fetches a list of items from a protected endpoint.
 * @returns {Promise<Array<object>>} A list of items.
 */
export const fetchItems = async () => {
  return request('/items', 'GET'); // Requires auth
};

/**
 * Creates a new item.
 * @param {object} itemData The data for the new item.
 * @returns {Promise<object>} The newly created item.
 */
export const createItem = async (itemData) => {
  return request('/items', 'POST', itemData); // Requires auth
};

/**
 * Fetches a specific item by ID.
 * @param {string} id The ID of the item.
 * @returns {Promise<object>} The item data.
 */
export const fetchItemById = async (id) => {
  return request(`/items/${id}`, 'GET'); // Requires auth
};

/**
 * Deletes a specific item by ID.
 * @param {string} id The ID of the item to delete.
 * @returns {Promise<object>} A success message or confirmation.
 */
export const deleteItem = async (id) => {
  return request(`/items/${id}`, 'DELETE'); // Requires auth
};

